starterCode.javascript:
// Define a function to project the fields of a document
function projectFields(doc) {
	var result = {};
	for (var key in doc) {
		if (doc.hasOwnProperty(key)) {
			result[key] = doc[key];
		}
	}
	return result;
}

starterCode.python:
class Solution:
	def projectFields(self, doc):
		result = {}
		for key in doc.keys():
			if key in doc:
				result[key] = doc[key]
		return result

